// Handle digits separately for efficiency and to avoid map population for 0-9
if (i >= '0' && i <= '9') {
    t = _parseUnsignedNumber(i);
} else {
    ValueTokenHandler handler = _valueTokenHandlers.get(i);
    if (handler != null) {
        t = handler.handle(i);
    } else {
        t = _handleUnexpectedValue(i);
    }
}
_nextToken = t;
return _currToken;
